const staticData = $getWorkflowStaticData('global');
staticData.totalProcessed = 0;
staticData.totalErrors = 0;
staticData.currentClient = '';

return [{ json: {
  rootFolderId: '1iEbSMlsHPX6Sg3y0J0znlT47ri78hk9_',
  spreadsheetId: '1cgctBCQVmqpfQKdomYLfGAWVwRjT1Qw0-dl9F5RzoOg',
  sheetGid: 1199154574,
  sheetName: 'Patientendaten'
}}];

const folders = $input.first().json.files || [];
const filtered = folders.filter(f => /^\d+$/.test(f.name));
if (!filtered.length) return [{ json: { empty: true } }];
return filtered.map(f => ({ json: { clientFolderId: f.id, clientFolderName: f.name } }));

const staticData = $getWorkflowStaticData('global');
const response = $input.first().json;
const prev = $('Split Clients').first().json;
const allFiles = response.files || [];

const allowed = ['.heic', '.jpg', '.jpeg', '.png'];
const mediaFiles = allFiles.filter(f =>
  !f.name.includes('_DONE') &&
  allowed.some(ext => f.name.toLowerCase().endsWith(ext))
);

staticData.currentClient = prev.clientFolderName;
staticData.clientData = { operations: {} };

if (!mediaFiles.length) return [{ json: { empty: true, clientFolderId: prev.clientFolderId, clientFolderName: prev.clientFolderName } }];
return mediaFiles.map(f => ({ json: {
  fileId: f.id, fileName: f.name, mimeType: f.mimeType,
  thumbnailLink: f.thumbnailLink || null,
  clientFolderId: prev.clientFolderId, clientFolderName: prev.clientFolderName
} }));

const fileData = $input.first().json;
const prev = $('Split Files').first().json;

let base64Image = null;
let mediaType = fileData.mimeType || 'image/jpeg';
const isHEIC = fileData.name.toLowerCase().endsWith('.heic');

// For HEIC: use high-res thumbnail (Google converts to JPEG)
// For JPEG/PNG: download actual file for maximum quality
if (!isHEIC) {
  try {
    const response = await this.helpers.httpRequestWithAuthentication.call(
      this, 'googleDriveOAuth2Api',
      { method: 'GET', url: `https://www.googleapis.com/drive/v3/files/${fileData.id}?alt=media`, encoding: 'arraybuffer', timeout: 30000 }
    );
    base64Image = Buffer.from(response).toString('base64');
  } catch (e) {}
}

// Fallback to high-res thumbnail (also primary path for HEIC)
if (!base64Image && fileData.thumbnailLink) {
  const highResUrl = fileData.thumbnailLink.replace(/=s\d+$/, '=s4096');
  try {
    const response = await this.helpers.httpRequest({ method: 'GET', url: highResUrl, encoding: 'arraybuffer' });
    base64Image = Buffer.from(response).toString('base64');
    mediaType = 'image/jpeg';
  } catch (e) {}
}

if (!base64Image) {
  return [{ json: { error: true, errorMessage: 'Cannot download image', fileName: fileData.name, fileId: fileData.id,
    clientFolderId: prev.clientFolderId, clientFolderName: prev.clientFolderName }}];
}

const PROMPT = `This is a photo of a German hospital monitor screen showing a patient medical report (BIA/body composition analysis). Extract ALL visible medical measurements and return ONLY this JSON object (no other text, no markdown, no code blocks):\n{\n  "client_id": "5-9 digit number visible in top area, or null",\n  "client_name": "patient full name if visible, or null",\n  "date": "date in DD.MM.YYYY format if visible, or null",\n  "Gewicht_kg": number or null, "Grosse_cm": number or null, "BMI_kg_m2": number or null,\n  "FM_kg": number or null, "FM_pct": number or null, "FMI_kg_m2": number or null,\n  "FFM_kg": number or null, "FFM_pct": number or null, "FFMI_kg_m2": number or null,\n  "SMM_kg": number or null, "R_ohm": number or null, "Xc_ohm": number or null,\n  "VAT_l": number or null, "WC_cm": number or null,\n  "phase_angle_deg": number or null, "perzentile": number or null,\n  "TBW_l": number or null, "TBW_pct": number or null,\n  "ECW_l": number or null, "ECW_pct": number or null, "ECW_TBW_pct": number or null\n}`;

return [{ json: {
  requestBody: {
    model: 'gpt-4o', max_tokens: 1500,
    messages: [
      { role: 'system', content: 'You are a medical data extraction assistant. Extract data from hospital monitor screen photos. Always respond with valid JSON only.' },
      { role: 'user', content: [
        { type: 'image_url', image_url: { url: 'data:' + mediaType + ';base64,' + base64Image, detail: 'high' } },
        { type: 'text', text: PROMPT }
      ]}
    ]
  },
  fileName: fileData.name, fileId: fileData.id,
  clientFolderId: prev.clientFolderId, clientFolderName: prev.clientFolderName, error: false
}}];

const staticData = $getWorkflowStaticData('global');
const resp = $input.first().json;
const prev = $('Split Files').first().json;

let parsed;
try {
  let rawText = resp.choices && resp.choices[0] ? resp.choices[0].message.content.trim() : '';
  const clean = rawText.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  staticData.totalErrors++;
  return [{ json: { parseError: true, fileName: prev.fileName, fileId: prev.fileId,
    clientFolderId: prev.clientFolderId, clientFolderName: prev.clientFolderName }}];
}

const date = parsed.date || 'unbekannt';
const cd = staticData.clientData;
if (!cd.client_name && parsed.client_name) cd.client_name = parsed.client_name;
if (!cd.client_id && parsed.client_id) cd.client_id = String(parsed.client_id).trim();
if (!cd.operations[date]) cd.operations[date] = {};

const FIELDS = ['Gewicht_kg','Grosse_cm','BMI_kg_m2','FM_kg','FM_pct','FMI_kg_m2','FFM_kg','FFM_pct','FFMI_kg_m2','SMM_kg','R_ohm','Xc_ohm','VAT_l','WC_cm','phase_angle_deg','perzentile','TBW_l','TBW_pct','ECW_l','ECW_pct','ECW_TBW_pct'];
const op = cd.operations[date];
for (const field of FIELDS) { if (parsed[field] !== null && parsed[field] !== undefined) op[field] = parsed[field]; }

staticData.totalProcessed++;

return [{ json: { parseError: false, fileName: prev.fileName, fileId: prev.fileId,
  clientFolderId: prev.clientFolderId, clientFolderName: prev.clientFolderName } }];

const staticData = $getWorkflowStaticData('global');
const config = $('Config').first().json;
const cd = staticData.clientData || {};
const ops = cd.operations || {};
const opDates = Object.keys(ops).filter(d => d !== 'unbekannt').sort((a, b) => {
  const p = d => { const [dd,mm,yy] = d.split('.'); return new Date(yy, mm-1, dd); };
  return p(a) - p(b);
});
if (ops['unbekannt']) opDates.push('unbekannt');

if (!opDates.length) return [{ json: { skipped: true, clientFolderName: staticData.currentClient } }];

const clientId = cd.client_id || staticData.currentClient;
const clientName = cd.client_name || '';

const FIELD_ORDER = ['Gewicht_kg','Grosse_cm','BMI_kg_m2','FM_kg','FM_pct','FMI_kg_m2','FFM_kg','FFM_pct','FFMI_kg_m2','SMM_kg','R_ohm','Xc_ohm','VAT_l','WC_cm','phase_angle_deg','perzentile','TBW_l','TBW_pct','ECW_l','ECW_pct','ECW_TBW_pct'];

return [{ json: {
  clientId, clientName, folderName: staticData.currentClient,
  operations: opDates.map((date, i) => ({ operationNumber: i+1, date, fields: ops[date] })),
  fieldOrder: FIELD_ORDER, totalOps: opDates.length,
  spreadsheetId: config.spreadsheetId, sheetGid: config.sheetGid, sheetName: config.sheetName
} }];

const sheetData = $input.first().json;
const prev = $('Write Client to Sheets').first().json;
const rows = sheetData.values || [];
const clientId = prev.clientId;
const clientName = prev.clientName;
const operations = prev.operations;
const FIELD_ORDER = prev.fieldOrder;
const sheetGid = prev.sheetGid;
const spreadsheetId = prev.spreadsheetId;
const sheetName = prev.sheetName;
const COLS_PER_OP = 21;
const START_COL = 2;

const headerRow = rows[1] || [];
let maxOpBlock = 0;
headerRow.forEach(cell => {
  const match = cell && String(cell).match(/^(\d+)\.\s*Operation/);
  if (match) maxOpBlock = Math.max(maxOpBlock, parseInt(match[1]));
});

const clientRowMap = {};
for (let i = 6; i < rows.length; i += 2) {
  const id = rows[i] && rows[i][0];
  if (id) clientRowMap[String(id).trim()] = i + 1;
}
const usedRows = Object.values(clientRowMap);
const nextFreeRow = usedRows.length > 0 ? Math.max(...usedRows) + 2 : 7;

let dateRow, dataRow;
if (clientRowMap[clientId]) { dateRow = clientRowMap[clientId]; dataRow = dateRow + 1; }
else { dateRow = nextFreeRow; dataRow = nextFreeRow + 1; }

const valueRanges = [];
const mergeRequests = [];

const SECTION_HEADERS = ['BMI','BMI','BMI','Fettmasse','Fettmasse','Fettmasse','Fettfreie Masse','Fettfreie Masse','Fettfreie Masse','Skelettmuskelmasse','BIVA','BIVA','Viszerales Fett & Taillenumfang','Viszerales Fett & Taillenumfang','Phasenwinkel','Phasenwinkel','Wasser','Wasser','Wasser','Wasser','Wasser'];
const FIELD_NAMES = ['Gewicht','Gr\u00f6\u00dfe','BMI','FM','FM','FMI','FFM','FFM','FFMI','SMM','R','Xc','VAT','Taillenumfang','\u03c6','Perzentile','TBW','TBW','ECW','ECW','ECW/TBW'];
const UNITS = ['kg','cm','kg/m\u00b2','kg','%','kg/m\u00b2','kg','%','kg/m\u00b2','kg','\u03a9','\u03a9','l','cm','\u00b0','\u2014','l','%','l','%','%'];

function colToLetter(col) { let l=''; while(col>=0){l=String.fromCharCode(65+(col%26))+l;col=Math.floor(col/26)-1;} return l; }

for (let opIdx = maxOpBlock; opIdx < operations.length; opIdx++) {
  const cs = START_COL + opIdx * COLS_PER_OP;
  const cl = colToLetter(cs); const ce = colToLetter(cs + COLS_PER_OP - 1);
  const r2 = new Array(COLS_PER_OP).fill(''); r2[0] = (opIdx+1)+'. Operation';
  valueRanges.push({range: sheetName+'!'+cl+'2:'+ce+'2', values: [r2]});
  valueRanges.push({range: sheetName+'!'+cl+'3:'+ce+'3', values: [SECTION_HEADERS]});
  valueRanges.push({range: sheetName+'!'+cl+'4:'+ce+'4', values: [FIELD_NAMES]});
  valueRanges.push({range: sheetName+'!'+cl+'5:'+ce+'5', values: [UNITS]});
  mergeRequests.push({mergeCells:{range:{sheetId:sheetGid,startRowIndex:1,endRowIndex:2,startColumnIndex:cs,endColumnIndex:cs+COLS_PER_OP},mergeType:'MERGE_ALL'}});
  [{s:0,c:3},{s:3,c:3},{s:6,c:3},{s:10,c:2},{s:12,c:2},{s:14,c:2},{s:16,c:5}].forEach(sec => {
    mergeRequests.push({mergeCells:{range:{sheetId:sheetGid,startRowIndex:2,endRowIndex:3,startColumnIndex:cs+sec.s,endColumnIndex:cs+sec.s+sec.c},mergeType:'MERGE_ALL'}});
  });
}

const maxCols = START_COL + Math.max(operations.length, maxOpBlock) * COLS_PER_OP;
const dateVals = new Array(maxCols).fill('');
const dataVals = new Array(maxCols).fill('');
dateVals[0] = clientId; dateVals[1] = clientName;

operations.forEach((op, idx) => {
  const co = START_COL + idx * COLS_PER_OP;
  dateVals[co] = 'Datum der Operation: ' + op.date;
  FIELD_ORDER.forEach((field, fi) => {
    const v = op.fields[field];
    if (v !== undefined && v !== null) dataVals[co + fi] = v;
  });
  mergeRequests.push({mergeCells:{range:{sheetId:sheetGid,startRowIndex:dateRow-1,endRowIndex:dateRow,startColumnIndex:co,endColumnIndex:co+COLS_PER_OP},mergeType:'MERGE_ALL'}});
});

valueRanges.push({range:sheetName+'!A'+dateRow+':'+colToLetter(maxCols-1)+dateRow, values:[dateVals]});
valueRanges.push({range:sheetName+'!A'+dataRow+':'+colToLetter(maxCols-1)+dataRow, values:[dataVals]});

return [{ json: { spreadsheetId, sheetName, sheetGid, valueRanges, mergeRequests, clientId, folderName: prev.folderName } }];
